tools.handler:
// Master tool: (input = { limit? }, api) → string
const audits = (api.storage.get('audits') || []).slice().reverse()
const limit = Math.max(1, Math.min(50, Number(input.limit) || 10))
if (!audits.length) return 'No QA audits recorded yet — audits run automatically when a task reaches review.'
return audits.slice(0, limit).map(a => {
  const when = new Date(a.at).toLocaleString()
  return `${a.verdict.toUpperCase().padEnd(7)} ${when} · "${a.title}"${a.detail ? ` — ${a.detail}` : ''}`
}).join('\n')

hooks.onTaskMoved:
// Fires on every board-column change: (input = { taskId, title, col, from }, api)
// When a task reaches review, spawn an independent auditor one-shot that
// re-verifies the acceptance criteria, and tell the task's watcher about it.
if (input.col !== 'review') return

const state = api.getState()
const task = state.tasks.find(t => t.id === input.taskId)
if (!task) return

// don't stack audits: skip if one is already running for this task
const audits = api.storage.get('audits') || []
if (audits.some(a => a.taskId === task.id && a.verdict === 'running')) return

const criteria = (task.criteria || []).map((c, i) => `${i + 1}. ${c}`).join('\n') || '(none recorded — judge from the description)'
const prompt = [
  'You are an independent QA auditor. Verify whether this task\'s acceptance criteria are ACTUALLY met in the current workspace — run checks and inspect files; never trust claims and never modify anything.',
  `Task: ${task.title}`,
  task.description ? `Description: ${task.description}` : '',
  `Acceptance criteria:\n${criteria}`,
  'Finish with exactly one line "QA VERDICT: pass" or "QA VERDICT: fail — <reason>", preceded by a short evidence list.',
].filter(Boolean).join('\n\n')

const quoted = "'" + prompt.replace(/'/g, "'\\''") + "'"
const sid = api.launchSession(`claude -p --permission-mode plan ${quoted}`, task.cwd || '', `qa·${task.title.slice(0, 14)}`)

api.storage.set('audits', [...audits, {
  taskId: task.id, title: task.title, at: Date.now(),
  sessionId: sid, verdict: sid ? 'running' : 'error', detail: sid ? '' : 'launch failed',
}].slice(-50))

if (sid) {
  api.tasks.chat(task.id, 'QA Gate: an independent auditor session is re-verifying the acceptance criteria. Hold the task in review until its verdict lands here.')
  api.notify('QA Gate', `Auditing "${task.title.slice(0, 50)}"`)
  api.logEvent(`QA audit started for "${task.title.slice(0, 40)}"`)
}

hooks.onSessionExit:
// Fires when any session exits: (input = { sessionId, name, code }, api)
// If it was one of our auditors, read its final output, record the verdict,
// report to the task's watcher chat, and bounce failing tasks back to work.
const audits = api.storage.get('audits') || []
const idx = audits.findIndex(a => a.sessionId === input.sessionId && a.verdict === 'running')
if (idx < 0) return

const out = api.sessions.readOutput(input.sessionId, 60)
const m = out.match(/QA VERDICT:\s*(pass|fail)\s*(?:[—-]\s*)?([^\n]*)/i)
const verdict = m ? m[1].toLowerCase() : (input.code === 0 ? 'unclear' : 'error')
const detail = m && m[2] ? m[2].trim() : ''

audits[idx] = { ...audits[idx], verdict, detail, doneAt: Date.now() }
api.storage.set('audits', audits)

const a = audits[idx]
const line = verdict === 'pass'
  ? 'QA Gate verdict: PASS — criteria independently verified. Safe to mark done.'
  : verdict === 'fail'
    ? `QA Gate verdict: FAIL — ${detail || 'see the auditor session output'}. Moving back to In progress; please address the findings.`
    : `QA Gate: the auditor exited without a clear verdict (${verdict}). Check its session output.`
api.tasks.chat(a.taskId, line)
api.notify(`QA ${verdict.toUpperCase()}`, a.title.slice(0, 60))
api.logEvent(`QA ${verdict} for "${a.title.slice(0, 40)}"`)
if (verdict === 'fail') api.tasks.move(a.taskId, 'progress')
